/**
 * @fileoverview PinInput component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * event handler abstractions, and Custom Element metadata.
 *
 * Used by:
 *   - PinInput.js (imports for SM config + handler dispatch)
 *   - JIT.defineComponent() (registers tokens + CE)
 *
 * @module module/PinInput.def
 */

import razyui from '../index.js';
import { PART } from './PinInput/constants.js';

/**
 * The definition object for the PinInput component.
 * @type {Object}
 */
export const PinInputDef = {
    name: 'PinInput',
    tag: 'rui-pin-input',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    tokens: {
        prefix: 'pi',
        tokens: {
            'gap':           { ref: 'spacing.2',        description: 'Gap between fields' },
            'field-width':   { value: '2.75rem',         description: 'Field width' },
            'field-height':  { value: '3.25rem',         description: 'Field height' },
            'border-width':  { value: '1.5px',           description: 'Field border width' },
            'radius':        { ref: 'radius.md',         description: 'Field border radius' },
            'font-size':     { value: '1.25rem',         description: 'Field font size' },
            'font-weight':   { value: '600',             description: 'Field font weight' },
            'font-mono':     { ref: 'font.mono',         description: 'Monospace font family' },
            'bg':            { ref: 'color.bg',           description: 'Field background' },
            'bg-raised':     { ref: 'color.bg-raised',    description: 'Filled field background' },
            'bg-inset':      { ref: 'color.bg-inset',     description: 'Disabled field background' },
            'text':          { ref: 'color.text',         description: 'Field text color' },
            'text-muted':    { ref: 'color.text-muted',   description: 'Placeholder color' },
            'border':        { ref: 'color.border',       description: 'Default border color' },
            'border-strong': { ref: 'color.border-strong', description: 'Hover/filled border' },
            'accent':        { ref: 'color.accent',       description: 'Focus accent color' },
            'accent-subtle': { ref: 'color.accent-subtle', description: 'Focus ring color' },
            'danger':        { ref: 'color.danger',        description: 'Error border color' },
            'success':       { ref: 'color.success',       description: 'Success border color' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine (component-level)
    // ═══════════════════════════════════════
    states: {
        initial: 'idle',
        states: {
            idle: {
                on: { FOCUS: 'focused', COMPLETE: 'complete', DISABLE: 'disabled' },
            },
            focused: {
                on: { BLUR: 'idle', COMPLETE: 'complete', DISABLE: 'disabled' },
            },
            complete: {
                on: { FOCUS: 'focused', CLEAR: 'idle', DISABLE: 'disabled' },
            },
            disabled: {
                on: { ENABLE: 'idle' },
            },
        },
        effects: {
            disabled(ctx) {
                const { el, fields } = ctx;
                razyui(el).addClass('is-disabled');
                el[0].setAttribute('aria-disabled', 'true');
                fields.forEach(f => { f.disabled = true; });
            },
            'disabled:exit'(ctx) {
                const { el, fields } = ctx;
                razyui(el).removeClass('is-disabled');
                el[0].removeAttribute('aria-disabled');
                fields.forEach(f => { f.disabled = false; });
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    template: {
        slots: {
            root:  { element: 'div',   classes: ['rz-pin-input'], role: 'group' },
            field: { element: 'input', classes: ['rz-pin-field'] },
        },
    },

    // ═══════════════════════════════════════
    //  Event Handlers (abstractions)
    // ═══════════════════════════════════════
    handlers: {
        field: {
            input(ctx, e, index) {
                const field = ctx.fields[index];
                const raw = field.value;
                let ch = ctx.isNumeric ? raw.replace(/[^0-9]/g, '') : raw.replace(/\s/g, '');
                ch = ch.slice(0, 1);

                // Invalid character typed → revert to previous valid value
                if (!ch && e.data) {
                    field.value = field.dataset.prev || '';
                    return;
                }

                field.value = ch;
                field.dataset.prev = ch;
                ctx.syncFromFields();

                // Auto-advance
                if (ch && index < ctx.length - 1) {
                    ctx.fields[index + 1].focus();
                    ctx.fields[index + 1].select();
                }
            },
            keydown(ctx, e, index) {
                // Block invalid printable characters before they modify the field
                if (e.key.length === 1 && !e.ctrlKey && !e.metaKey) {
                    if (ctx.isNumeric && !/[0-9]/.test(e.key)) {
                        e.preventDefault();
                        return;
                    }
                }

                if (e.key === 'Backspace') {
                    if (!ctx.fields[index].value && index > 0) {
                        ctx.fields[index - 1].value = '';
                        ctx.fields[index - 1].focus();
                        ctx.syncFromFields();
                        e.preventDefault();
                    }
                } else if (e.key === 'ArrowLeft' && index > 0) {
                    e.preventDefault();
                    ctx.fields[index - 1].focus();
                    ctx.fields[index - 1].select();
                } else if (e.key === 'ArrowRight' && index < ctx.length - 1) {
                    e.preventDefault();
                    ctx.fields[index + 1].focus();
                    ctx.fields[index + 1].select();
                } else if (e.key === 'Delete') {
                    ctx.fields[index].value = '';
                    ctx.syncFromFields();
                }
            },
            focus(ctx, e, index) {
                ctx.fields[index].select();
                razyui(ctx.fields[index]).addClass('is-focused');
            },
            blur(ctx, e, index) {
                razyui(ctx.fields[index]).removeClass('is-focused');
            },
            paste(ctx, e, index) {
                e.preventDefault();
                const pasted = (e.clipboardData || window.clipboardData).getData('text').trim();
                let chars = pasted.split('');
                chars = ctx.isNumeric
                    ? chars.filter(c => /[0-9]/.test(c))
                    : chars.filter(c => /\S/.test(c));

                for (let j = 0; j < chars.length && (index + j) < ctx.length; j++) {
                    ctx.fields[index + j].value = chars[j];
                    ctx.fields[index + j].dataset.prev = chars[j];
                }

                ctx.syncFromFields();

                const nextEmpty = ctx.fields.findIndex(f => !f.value);
                if (nextEmpty >= 0) {
                    ctx.fields[nextEmpty].focus();
                } else {
                    ctx.fields[ctx.length - 1].focus();
                }
            },
        },
    },

    // ═══════════════════════════════════════
    //  Variants
    // ═══════════════════════════════════════
    variants: {
        compact: { description: 'Smaller fields for tight layouts' },
        large:   { description: 'Larger fields for touch-friendly input' },
    },

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    observedAttrs: ['length', 'type', 'masked', 'disabled', 'placeholder', 'auto-focus'],
    attrMap: {
        'auto-focus': 'autoFocus',
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.FIELD]: PART.FIELD,
    },

    styles: {},
};

export default PinInputDef;
