/**
 * @fileoverview PinInput state — reactive state wiring + field sync effect.
 * @module module/PinInput/state
 */

import razyui from '../../index.js';
import { CLS } from './constants.js';

/**
 * Create the reactive state for a PinInput instance.
 * Returns the ref, setState function, and wires an effect that keeps
 * DOM field values in sync with the reactive `value` string.
 *
 * @param {Function} stateFn — razyui.state
 * @param {HTMLInputElement[]} fields — array of input elements
 * @returns {{ ref: object, setState: Function }}
 */
export function createReactiveState(stateFn, fields) {
    const stateSet = stateFn({ value: '' });
    const ref      = stateSet[0];
    const setState = stateSet[1];

    // Effect: sync field values from state
    stateSet.effect(() => {
        const val = ref.value;
        fields.forEach((f, i) => {
            const ch = val[i] || '';
            if (f.value !== ch) f.value = ch;
            razyui(f).toggleClass(CLS.FILLED, ch !== '');
        });
    });

    return { ref, setState };
}
