/**
 * @fileoverview PinInput view — DOM setup / teardown.
 * @module module/PinInput/view
 */

import { CLS, ARIA, DEFAULTS, PART } from './constants.js';

/**
 * Build the PIN input DOM: wrapper classes, ARIA, and individual input fields.
 *
 * @param {Elements} el — root container (razyui Elements)
 * @param {object} cfg — user configuration
 * @param {number} len — number of PIN fields
 * @returns {HTMLInputElement[]} array of created input elements
 */
export function buildDOM(el, cfg, len) {
    const masked      = !!cfg.masked;
    const placeholder = cfg.placeholder ?? DEFAULTS.placeholder;
    const isNumeric   = (cfg.type ?? DEFAULTS.type) === 'numeric';

    // ── Container setup ──
    el.addClass('pin-input ' + CLS.ROOT)
      .html('')
      .setAttr({ 'role': ARIA.ROLE, 'aria-label': ARIA.LABEL });
    PART.ROOT.apply(el);
    if (cfg.disabled) el.addClass(CLS.DISABLED);

    const fields = [];

    for (let i = 0; i < len; i++) {
        const input = PART.FIELD.create({
            type: masked ? 'password' : 'text',
            inputMode: isNumeric ? 'numeric' : 'text',
            maxLength: 1,
            placeholder,
            autocomplete: DEFAULTS.autocomplete,
            'aria-label': `Digit ${i + 1} of ${len}`,
        });

        if (cfg.disabled) input.setAttr({ disabled: true });

        el.append(input);
        fields.push(input[0]);
    }

    return fields;
}

/**
 * Cleanup and restore the original element.
 *
 * @param {Elements} el — root container (razyui Elements)
 */
export function cleanupDOM(el) {
    el.removeClass('pin-input', CLS.ROOT, CLS.DISABLED)
      .removeAttr(['role', 'aria-label'])
      .html('');
}
